def solve(grid):
    import numpy as np
    g = np.array(grid)
    H, W = g.shape
    eights = np.argwhere(g == 8)
    r_min, c_min = eights.min(axis=0)
    r_max, c_max = eights.max(axis=0)
    K_c = None
    for K in range(W, 2*W):
        ok = True; count = 0
        for r in range(H):
            for c in range(W):
                if g[r, c] == 8: continue
                c2 = K - c
                if 0 <= c2 < W and g[r, c2] != 8:
                    count += 1
                    if g[r, c] != g[r, c2]: ok = False; break
            if not ok: break
        if ok and count > 50: K_c = K; break
    K_r = None
    for K in range(H, 2*H):
        ok = True; count = 0
        for r in range(H):
            r2 = K - r
            if not (0 <= r2 < H): continue
            for c in range(W):
                if g[r, c] == 8 or g[r2, c] == 8: continue
                count += 1
                if g[r, c] != g[r2, c]: ok = False; break
            if not ok: break
        if ok and count > 50: K_r = K; break
    result = g.copy()
    for r in range(r_min, r_max + 1):
        for c in range(c_min, c_max + 1):
            if K_c is not None:
                c2 = K_c - c
                if 0 <= c2 < W and g[r, c2] != 8: result[r, c] = g[r, c2]; continue
            if K_r is not None:
                r2 = K_r - r
                if 0 <= r2 < H and g[r2, c] != 8: result[r, c] = g[r2, c]; continue
            if K_r is not None and K_c is not None:
                r2 = K_r - r; c2 = K_c - c
                if 0 <= r2 < H and 0 <= c2 < W and g[r2, c2] != 8: result[r, c] = g[r2, c2]; continue
    return result[r_min:r_max+1, c_min:c_max+1].tolist()
